mapper.insert:
		/*
			 토론 댓글 등록
			 ForumCmntDAO.insertCmnt
		*/
        INSERT INTO TB_LMS_DSCS_CMNT (
              DSCS_CMNT_ID
            , DSCS_ATCL_ID
            , USER_ID
            , UP_CMNT_ID
            , CMNT_CTS
            , CMNT_CTS_LEN
            , RSPNS_REQYN
            , EMT_TYCD
            , DELYN
            , RGTR_ID
            , REG_DTTM
            , MDFR_ID
            , MOD_DTTM
        ) VALUES (
              #{cmntSn}
            , #{atclSn}
            , #{rgtrId}
            , #{parCmntSn}
            , #{cmntCts}
            , #{cmntCtsLen}
            , #{ansReqYn}
            , TO_CHAR(#{emoticonNo})
            , 'N'
            , #{rgtrId}
            , FN_DTTM()
            , #{mdfrId}
            , FN_DTTM()
        )

mapper.update:
		/*
			 토론방 댓글 수정
			 ForumCmntDAO.updateCmnt
		*/
        UPDATE TB_LMS_DSCS_CMNT
        SET CMNT_CTS = #{cmntCts}
          , CMNT_CTS_LEN = #{cmntCtsLen}
          , RSPNS_REQYN = #{ansReqYn}
          , MOD_DTTM = FN_DTTM()
          , MDFR_ID = #{mdfrId}
        WHERE DSCS_CMNT_ID = #{cmntSn}

		/*
			 토론방 댓글 삭제
			 ForumCmntDAO.deleteCmnt
		*/
        UPDATE TB_LMS_DSCS_CMNT
        SET DELYN = 'Y'
          , MOD_DTTM = FN_DTTM()
          , MDFR_ID = #{mdfrId}
        WHERE DSCS_CMNT_ID = #{cmntSn}
